module four_input_one_output (
    input a,
    input b,
    input c,
    input d,
    output reg invalid_out
);

always @(*) begin
    if (a) begin
        invalid_out = 1;
    end else if (b) begin
        invalid_out = 1;
    end else if (c) begin
        invalid_out = 1;
    end else if (d) begin
        invalid_out = 1;
    end else begin
        invalid_out = 0;
    end
end

endmodule
